func clipboardPreview(s string, limit int) (preview string, truncated bool) {
	if limit < 0 {
		limit = 0
	}
	clean := strings.ReplaceAll(s, "\r\n", "\n")
	clean = strings.ReplaceAll(clean, "\r", "\n")
	if utf8.RuneCountInString(clean) <= limit {
		return clean, false
	}
	var b strings.Builder
	count := 0
	for _, r := range clean {
		if count >= limit {
			break
		}
		b.WriteRune(r)
		count++
	}
	return b.String(), true
}

